    // defino mi recolector para guardar los errores sintacticos
    private ReportCollector collector;

    // constructor para que mi aplicacion principal pueda inyectar mi recolector
    // especifico java_cup.runtime.Scanner para que no choque con java.util.Scanner
    public GoLiteParser(java_cup.runtime.Scanner s, ReportCollector collector) {
        super(s);
        this.collector = collector;
    }

    // intercepto los errores sintacticos normales para mandarlos a mi gui
    @Override
    public void syntax_error(Symbol s) {
        String lexeme = (s.value != null) ? s.value.toString() : "EOF";
        String message = "no esperaba esto: '" + lexeme + "'. fallo de sintaxis.";
        
        if (collector != null) {
            collector.addError(ErrorType.SYNTACTIC, s.left, s.right, message);
        } else {
            System.err.println("error sintactico en la linea " + s.left + ", columna " + s.right + ". " + message);
        }
    }

    // intercepto los errores sintacticos que ya no puedo salvar
    @Override
    public void unrecovered_syntax_error(Symbol s) throws java.lang.Exception {
        if (collector != null) {
            collector.addError(ErrorType.SYNTACTIC, s.left, s.right, "error sintactico irrecuperable. detuve el parser.");
        } else {
            System.err.println("error sintactico irrecuperable.");
        }
    }

    // CUP por defecto exige 3 tokens limpios consecutivos despues de un error
    // antes de confirmar que se recupero. Lo bajo a 1 para que la recuperacion
    // en modo panico sea mas agresiva y no se quede esperando demasiado.
    @Override
    public int error_sync_size() {
        return 1;
    }


